pub enum Method {
    Get,
    Post,
    Put,
    Patch,
    Delete,
    Head,
    Options,
    Connect,
    Trace,
}

impl From<spikard::Method> for Method {
    fn from(val: spikard::Method) -> Self {
        match val {
            spikard::Method::Get => Self::Get,
            spikard::Method::Post => Self::Post,
            spikard::Method::Put => Self::Put,
            spikard::Method::Patch => Self::Patch,
            spikard::Method::Delete => Self::Delete,
            spikard::Method::Head => Self::Head,
            spikard::Method::Options => Self::Options,
            spikard::Method::Connect => Self::Connect,
            spikard::Method::Trace => Self::Trace,
        }
    }
}

impl Method {
    pub fn to_string(&self) -> String {
        match self {
            Self::Get => "Get".to_string(),
            Self::Post => "Post".to_string(),
            Self::Put => "Put".to_string(),
            Self::Patch => "Patch".to_string(),
            Self::Delete => "Delete".to_string(),
            Self::Head => "Head".to_string(),
            Self::Options => "Options".to_string(),
            Self::Connect => "Connect".to_string(),
            Self::Trace => "Trace".to_string(),
        }
    }
}

pub enum SecuritySchemeInfo {
    Http,
    ApiKey,
}

impl From<spikard_http::SecuritySchemeInfo> for SecuritySchemeInfo {
    fn from(val: spikard_http::SecuritySchemeInfo) -> Self {
        match val {
            spikard_http::SecuritySchemeInfo::Http { .. } => Self::Http,
            spikard_http::SecuritySchemeInfo::ApiKey { .. } => Self::ApiKey,
        }
    }
}

impl SecuritySchemeInfo {
    pub fn to_string(&self) -> String {
        match self {
            Self::Http => "http".to_string(),
            Self::ApiKey => "apiKey".to_string(),
        }
    }
}

